package com.example.profileupload.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;
import org.springframework.web.multipart.MultipartFile;

import jakarta.annotation.PostConstruct;
import java.io.IOException;
import java.nio.file.*;
import java.util.Set;
import java.util.UUID;

@Service
public class FileStorageService {

    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
            "image/jpeg",
            "image/png",
            "image/gif",
            "image/webp",
            "image/bmp",
            "image/tiff"
    );

    private final Path uploadDir;

    public FileStorageService(@Value("${app.upload-dir:uploads}") String uploadDir) {
        this.uploadDir = Paths.get(uploadDir).toAbsolutePath().normalize();
    }

    @PostConstruct
    public void init() throws IOException {
        Files.createDirectories(uploadDir);
    }

    public String storeProfilePicture(MultipartFile file) {
        if (file == null || file.isEmpty()) {
            throw new IllegalArgumentException("File is required");
        }

        String contentType = file.getContentType();
        if (contentType == null || !ALLOWED_CONTENT_TYPES.contains(contentType.toLowerCase())) {
            throw new IllegalArgumentException("Unsupported image format");
        }

        String originalFilename = StringUtils.cleanPath(file.getOriginalFilename() == null ? "" : file.getOriginalFilename());
        String extension = getFileExtension(originalFilename, contentType);

        String filename = UUID.randomUUID().toString() + extension;
        Path targetLocation = uploadDir.resolve(filename).normalize();

        try {
            Files.copy(file.getInputStream(), targetLocation, StandardCopyOption.REPLACE_EXISTING);
        } catch (IOException e) {
            throw new RuntimeException("Could not store file", e);
        }

        return "/uploads/" + filename;
    }

    private String getFileExtension(String originalFilename, String contentType) {
        String ext = "";

        if (StringUtils.hasText(originalFilename) && originalFilename.contains(".")) {
            ext = originalFilename.substring(originalFilename.lastIndexOf('.')).toLowerCase();
        } else if ("image/jpeg".equalsIgnoreCase(contentType)) {
            ext = ".jpg";
        } else if ("image/png".equalsIgnoreCase(contentType)) {
            ext = ".png";
        } else if ("image/gif".equalsIgnoreCase(contentType)) {
            ext = ".gif";
        } else if ("image/webp".equalsIgnoreCase(contentType)) {
            ext = ".webp";
        } else if ("image/bmp".equalsIgnoreCase(contentType)) {
            ext = ".bmp";
        } else if ("image/tiff".equalsIgnoreCase(contentType)) {
            ext = ".tiff";
        }

        return ext;
    }
}

